// ========== NAVIGATION ==========
const PAGES=['home','about','menu','booking','gallery','events','map'];

function showPage(id){
  PAGES.forEach(p=>{
    const el=document.getElementById('page-'+p);
    if(!el)return;
    if(p===id){
      el.style.display='block';
      el.classList.add('active');
      requestAnimationFrame(()=>el.style.opacity='1');
    } else {
      el.style.opacity='0';
      el.classList.remove('active');
      setTimeout(()=>{if(!el.classList.contains('active'))el.style.display='none';},350);
    }
  });
  document.querySelectorAll('.nav-links a').forEach(a=>a.classList.toggle('active',a.dataset&&a.dataset.page===id));
  window.scrollTo({top:0,behavior:'smooth'});
  setTimeout(initAnim,80);
  if(id==='booking'){drawPlan();updateMyBookings();populateTableSelect();}
  if(id==='menu')filterMenu('all',document.querySelector('.mcat'));
  if(id==='home')renderPopular();
}

function toggleMobileMenu(){
  const menu=document.getElementById('mobileMenu');
  const hamburger=document.querySelector('.hamburger');
  const isOpen=menu.classList.toggle('open');
  hamburger.classList.toggle('open',isOpen);
  hamburger.setAttribute('aria-expanded',isOpen);
  document.body.style.overflow=isOpen?'hidden':'';
}

// ========== SCROLL EFFECTS ==========
function initAnim(){
  document.querySelectorAll('.fi').forEach(el=>{
    const r=el.getBoundingClientRect();
    if(r.top<window.innerHeight-40)el.classList.add('v');
  });
}
window.addEventListener('scroll',initAnim);

// Nav scroll effect
let lastScroll=0;
window.addEventListener('scroll',()=>{
  const nav=document.getElementById('nav');
  nav.classList.toggle('scrolled',window.scrollY>50);
  const btt=document.getElementById('backToTop');
  btt.classList.toggle('visible',window.scrollY>400);
  lastScroll=window.scrollY;
});

// ========== IMAGES ==========
function loadImages(){
  const heroBg=document.getElementById('heroBg');
  if(heroBg&&PHOTOS.building)heroBg.style.backgroundImage='url('+PHOTOS.building+')';
  const pc1=document.getElementById('pcImg1');if(pc1&&PHOTOS.pond)pc1.src=PHOTOS.pond;
  const pc2=document.getElementById('pcImg2');if(pc2&&PHOTOS.terrace)pc2.src=PHOTOS.terrace;
  const pc3=document.getElementById('pcImg3');if(pc3&&PHOTOS.building)pc3.src=PHOTOS.building;
  const aph1=document.querySelector('#aph1 img');if(aph1&&PHOTOS.pond)aph1.src=PHOTOS.pond;
  const aph2=document.querySelector('#aph2 img');if(aph2&&PHOTOS.hall)aph2.src=PHOTOS.hall;
  const aph3=document.querySelector('#aph3 img');if(aph3&&PHOTOS.terrace)aph3.src=PHOTOS.terrace;
}
setTimeout(loadImages,30);
setTimeout(initAnim,150);

// ========== GALLERY ==========
let galleryItems=[];

async function loadGallery(){
  try{
    const r=await fetch(API_BASE+'/api/gallery');
    const data=await r.json();
    galleryItems=data.gallery||[];
  }catch(e){galleryItems=[];}
  renderGallery();
}

function renderGallery(){
  const grid=document.getElementById('galGrid');
  if(!grid)return;
  const defaultItems=[
    {src:PHOTOS.pond,lbl:'Пруд с золотыми рыбками'},
    {src:PHOTOS.hall,lbl:'Зал · Два этажа'},
    {src:PHOTOS.terrace,lbl:'Летняя терраса'},
    {src:PHOTOS.building,lbl:'Фасад Eden'},
  ];
  const allItems=galleryItems.length>0?galleryItems.map(g=>({src:g.src,lbl:g.label||''})):defaultItems;
  grid.innerHTML=allItems.map(it=>`<div class="gitem">${it.src?`<img src="${it.src}" alt="${it.lbl}" loading="lazy">`:`<div style="width:100%;height:100%;background:var(--bg2);display:flex;align-items:center;justify-content:center;color:var(--muted);font-size:14px">${it.lbl}</div>`}<div class="gitem-overlay"></div><div class="gitem-lbl">${it.lbl}</div></div>`).join('');
}

