const catNames={salad:'Салаты',zakuski:'Закуски',main:'Горячее',soup:'Супы',dessert:'Десерты',drink:'Напитки'};
const catColors={salad:'#E8F0E0',zakuski:'#F5E6DC',main:'#F8E4DC',soup:'#E0EBF5',dessert:'#F0E4F2',drink:'#E0F0EE'};

let currentFilter='all',currentSort='default',currentSearch='';

function getFilteredMenu(){
  let items=currentFilter==='all'?MENU:MENU.filter(i=>i.cat===currentFilter);
  if(currentSearch){
    const q=currentSearch.toLowerCase();
    items=items.filter(i=>i.name.toLowerCase().includes(q)||i.desc.toLowerCase().includes(q));
  }
  if(currentSort==='price-asc')items=[...items].sort((a,b)=>a.price-b.price);
  else if(currentSort==='price-desc')items=[...items].sort((a,b)=>b.price-a.price);
  else if(currentSort==='name')items=[...items].sort((a,b)=>a.name.localeCompare(b.name,'ru'));
  return items;
}

function renderMenu(){
  const items=getFilteredMenu();
  const grid=document.getElementById('menuGrid');
  const empty=document.getElementById('menuEmpty');
  if(!grid)return;
  if(items.length===0){
    grid.innerHTML='';
    if(empty)empty.style.display='block';
    return;
  }
  if(empty)empty.style.display='none';
  grid.innerHTML=items.map((item,i)=>`
    <div class="mitem" onclick='openMenuModal(${i})' tabindex="0" role="button" aria-label="${item.name}, ${formatPrice(item.price)} тг">
      <div class="mitem-img" style="background:${catColors[item.cat]}">${item.emoji}</div>
      <div class="mitem-body">
        <div class="mcat-tag">${catNames[item.cat]}</div>
        <div class="mname">${item.name}</div>
        <div class="mdesc">${item.desc}</div>
        <div class="mprice">${formatPrice(item.price)}<span>тг</span></div>
      </div>
    </div>`).join('');
  window.currentMenuItems=items;
}

function filterMenu(cat,el){
  currentFilter=cat;
  document.querySelectorAll('.mcat').forEach(b=>{b.classList.remove('on');b.setAttribute('aria-selected','false');});
  if(el){el.classList.add('on');el.setAttribute('aria-selected','true');}
  renderMenu();
}

function sortMenu(sort,el){
  currentSort=sort;
  document.querySelectorAll('.sort-btn').forEach(b=>b.classList.remove('on'));
  if(el)el.classList.add('on');
  renderMenu();
}

function formatPrice(n){return n.toString().replace(/\B(?=(\d{3})+(?!\d))/g,' ');}

