// ========== MENU MODAL ==========
let modalQty=1;

function openMenuModal(idx){
  const item=window.currentMenuItems?window.currentMenuItems[idx]:null;
  if(!item)return;
  modalQty=1;
  const modalImg=document.getElementById('modalImg');
  modalImg.style.background=catColors[item.cat];
  const imgHtml=item.img?`<img src="${item.img}" alt="${item.name}" style="width:100%;height:100%;object-fit:cover">`:item.emoji;
  modalImg.innerHTML='<button class="modal-close" onclick="closeMenuModal()" aria-label="Закрыть">&times;</button>'+imgHtml;
  document.getElementById('modalCat').textContent=catNames[item.cat];
  document.getElementById('modalName').textContent=item.name;
  document.getElementById('modalPrice').textContent=formatPrice(item.price)+' тг';
  document.getElementById('modalDesc').textContent=item.desc;
  document.getElementById('modalQtyInput').value=1;
  document.getElementById('menuModal').classList.add('open');
  document.body.style.overflow='hidden';
  window._modalItem=item;
}

function closeMenuModal(){
  document.getElementById('menuModal').classList.remove('open');
  document.body.style.overflow='';
}

function changeModalQty(delta){
  modalQty=Math.max(1,Math.min(20,modalQty+delta));
  document.getElementById('modalQtyInput').value=modalQty;
}

function addToCartFromModal(){
  if(!window._modalItem)return;
  addToCart(window._modalItem,modalQty);
  closeMenuModal();
}

// ========== CART ==========
let cart=JSON.parse(localStorage.getItem('eden_cart')||'[]');

function saveCart(){
  localStorage.setItem('eden_cart',JSON.stringify(cart));
  updateCartUI();
}

function addToCart(item,qty=1){
  const existing=cart.find(c=>c.name===item.name);
  if(existing){existing.qty+=qty;}
  else{cart.push({...item,qty});}
  saveCart();
  showToast(`${item.name} добавлен в корзину`);
  if(!document.getElementById('cartSidebar').classList.contains('open')){
    toggleCart();
  }
}

function removeFromCart(idx){
  cart.splice(idx,1);
  saveCart();
}

function changeCartQty(idx,delta){
  cart[idx].qty+=delta;
  if(cart[idx].qty<=0)cart.splice(idx,1);
  saveCart();
}

function clearCart(){
  cart=[];
  saveCart();
}

function toggleCart(){
  const sidebar=document.getElementById('cartSidebar');
  const overlay=document.getElementById('cartOverlay');
  const isOpen=sidebar.classList.toggle('open');
  overlay.classList.toggle('open',isOpen);
  document.body.style.overflow=isOpen?'hidden':'';
}

function updateCartUI(){
  const itemsEl=document.getElementById('cartItems');
  const emptyEl=document.getElementById('cartEmpty');
  const footerEl=document.getElementById('cartFooter');
  const countEl=document.getElementById('cartCount');
  const btnEl=document.getElementById('cartBtn');
  const totalEl=document.getElementById('cartTotal');

  const totalQty=cart.reduce((s,c)=>s+c.qty,0);
  const totalPrice=cart.reduce((s,c)=>s+c.price*c.qty,0);

  countEl.textContent=totalQty;
  btnEl.style.display=totalQty>0?'flex':'none';

  if(cart.length===0){
    if(emptyEl)emptyEl.style.display='block';
    if(footerEl)footerEl.style.display='none';
    itemsEl.innerHTML='';
    itemsEl.appendChild(emptyEl||document.createElement('div'));
    return;
  }

  if(emptyEl)emptyEl.style.display='none';
  if(footerEl)footerEl.style.display='block';
  totalEl.textContent=formatPrice(totalPrice)+' тг';

  itemsEl.innerHTML=cart.map((item,i)=>`
    <div class="cart-item">
      <div class="cart-item-emoji">${item.emoji}</div>
      <div class="cart-item-info">
        <div class="cart-item-name">${item.name}</div>
        <div class="cart-item-price">${formatPrice(item.price)} тг</div>
      </div>
      <div class="cart-item-qty">
        <button onclick="changeCartQty(${i},-1)" aria-label="Уменьшить">&minus;</button>
        <span>${item.qty}</span>
        <button onclick="changeCartQty(${i},1)" aria-label="Увеличить">+</button>
      </div>
      <button class="cart-item-remove" onclick="removeFromCart(${i})" aria-label="Удалить">&times;</button>
    </div>`).join('');
}

// ========== ORDER ==========
function toggleTableSelect(){
  const type=document.querySelector('input[name="orderType"]:checked').value;
  const wrap=document.getElementById('tableSelectWrap');
  if(wrap)wrap.style.display=type==='here'?'block':'none';
}

function populateTableSelect(){
  const sel=document.getElementById('orderTableSelect');
  if(!sel)return;
  sel.innerHTML='<option value="">Выберите столик</option>';
  FLOORS[cf].tables.forEach(t=>{
    const booked=bookings.some(b=>b.floor===cf&&b.tableId===t.id);
    if(!booked){
      const label=t.name||('№'+t.id+' ('+t.s+' мест)');
      sel.innerHTML+='<option value="'+t.id+'">'+label+'</option>';
    }
  });
}

function submitOrder(){
  if(cart.length===0){showToast('Корзина пуста');return;}
  const orderType=document.querySelector('input[name="orderType"]:checked').value;
  const total=cart.reduce((s,c)=>s+c.price*c.qty,0);

  const order={type:orderType,items:[...cart],total};
  if(orderType==='here'){
    const tableVal=document.getElementById('orderTableSelect')?.value;
    if(!tableVal){showToast('Выберите столик');return;}
    order.tableId=parseInt(tableVal);
    order.floor=cf;
    const fd=FLOORS[cf];
    const table=fd.tables.find(t=>t.id===order.tableId);
    order.tableLabel=table?(table.name||('№'+table.id)):'';
  }

  fetch(API_BASE+'/api/orders',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(order)})
    .then(r=>r.json())
    .then(data=>{
      if(!data.ok){showToast('Ошибка заказа');return;}
      document.getElementById('orderNum').textContent=data.order.id;
      const tableInfo=order.tableLabel?' — '+order.tableLabel:'';
      document.getElementById('orderTypeLabel').textContent=orderType==='here'?'Заказ в зале'+tableInfo:'Заказ с собой';
      document.getElementById('orderStep3').textContent=orderType==='here'?'Ожидайте в зале — официант принесёт ваш заказ':'Заберите заказ на выносе у стойки';
      const modal=document.getElementById('orderModal');
      modal.style.display='flex';
      cart=[];
      saveCart();
      toggleCart();
    })
    .catch(()=>showToast('Ошибка сети'));
}

async function exportData(){
  const [bksData,ordsData]=await Promise.all([
    fetch(API_BASE+'/api/bookings').then(r=>r.json()).catch(()=>({bookings:[]})),
    fetch(API_BASE+'/api/orders').then(r=>r.json()).catch(()=>({orders:[]}))
  ]);
  const data={bookings:bksData.bookings||[],orders:ordsData.orders||[],exportDate:new Date().toISOString()};
  const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='eden-data-'+new Date().toISOString().split('T')[0]+'.json';a.click();
}

// ========== TOAST ==========
function showToast(msg){
  let toast=document.querySelector('.toast');
  if(!toast){toast=document.createElement('div');toast.className='toast';document.body.appendChild(toast);}
  toast.textContent=msg;
  toast.classList.add('show');
  setTimeout(()=>toast.classList.remove('show'),2500);
}

