function drawPlan(){
  if(!pctx)return;
  const fd=FLOORS[cf];PC.width=fd.w;PC.height=fd.h;
  pctx.fillStyle='#FAF8F4';pctx.fillRect(0,0,fd.w,fd.h);
  pctx.strokeStyle='rgba(184,147,90,.06)';pctx.lineWidth=1;
  for(let x=0;x<fd.w;x+=40){pctx.beginPath();pctx.moveTo(x,0);pctx.lineTo(x,fd.h);pctx.stroke();}
  for(let y=0;y<fd.h;y+=40){pctx.beginPath();pctx.moveTo(0,y);pctx.lineTo(fd.w,y);pctx.stroke();}
  (fd.features||[]).forEach(f=>{
    if(f.t==='window'||f.t==='balcony'){pctx.fillStyle='rgba(120,180,220,.4)';pctx.fillRect(f.x,f.y,f.w,f.h);}
    if(f.t==='lake'){
      pctx.beginPath();pctx.ellipse(f.x,f.y,f.rx,f.ry,0,0,Math.PI*2);
      const lg=pctx.createRadialGradient(f.x,f.y,0,f.x,f.y,f.rx);lg.addColorStop(0,'#7ec8f0');lg.addColorStop(.5,'#3a8ab8');lg.addColorStop(1,'#1a5580');
      pctx.fillStyle=lg;pctx.fill();pctx.strokeStyle='rgba(60,140,180,.5)';pctx.lineWidth=1.5;pctx.stroke();
      pctx.fillStyle='#2a6a90';pctx.font='bold 13px Inter';pctx.textAlign='center';pctx.fillText('\uD83C\uDF0A '+f.label,f.x,f.y+4);
    }
    if(f.t==='stairs'){pctx.fillStyle='#E8E0D0';pctx.fillRect(f.x,f.y,f.w,f.h);pctx.strokeStyle='rgba(184,147,90,.25)';pctx.lineWidth=1;pctx.strokeRect(f.x,f.y,f.w,f.h);pctx.fillStyle='#8B7355';pctx.font='10px Inter';pctx.textAlign='center';pctx.fillText(f.label,f.x+f.w/2,f.y+f.h/2+4);}
    if(f.t==='bar'){pctx.fillStyle='#E8DCC8';pctx.fillRect(f.x,f.y,f.w,f.h);pctx.strokeStyle='rgba(184,147,90,.3)';pctx.lineWidth=1;pctx.strokeRect(f.x,f.y,f.w,f.h);pctx.fillStyle='#8B6914';pctx.font='11px Inter';pctx.textAlign='center';pctx.fillText(f.label,f.x+f.w/2,f.y+f.h/2+4);}
    if(f.t==='entrance'){pctx.fillStyle='rgba(120,180,140,.2)';pctx.fillRect(f.x,f.y,f.w,f.h);pctx.strokeStyle='rgba(45,122,79,.35)';pctx.lineWidth=1;pctx.strokeRect(f.x,f.y,f.w,f.h);pctx.fillStyle='#2D7A4F';pctx.font='10px Inter';pctx.textAlign='center';pctx.fillText(f.label,f.x+f.w/2,f.y+f.h/2+4);}
    if(f.t==='vip'){pctx.fillStyle='rgba(184,147,90,.08)';pctx.fillRect(f.x,f.y,f.w,f.h);pctx.strokeStyle='rgba(184,147,90,.2)';pctx.lineWidth=1;pctx.strokeRect(f.x,f.y,f.w,f.h);pctx.fillStyle='#8B6914';pctx.font='10px Inter';pctx.textAlign='center';pctx.fillText(f.label,f.x+f.w/2,f.y+f.h/2+4);}
  });
  pctx.strokeStyle='rgba(184,147,90,.15)';pctx.lineWidth=1.5;pctx.strokeRect(1,1,fd.w-2,fd.h-2);

  // Merge hardcoded bookings with localStorage bookings
  const bookedTables=new Set();
  bookings.forEach(b=>{if(b.floor===cf)bookedTables.add(b.tableId);});

  fd.tables.forEach(t=>{
    if(!t.w||t.h<10)return;
    const isSel=sel&&sel.floor===cf&&sel.id===t.id;
    const isBooked=t.b||bookedTables.has(t.id);
    pctx.beginPath();if(pctx.roundRect)pctx.roundRect(t.x,t.y,t.w,t.h,8);else pctx.rect(t.x,t.y,t.w,t.h);
    pctx.fillStyle=isBooked?'rgba(163,48,48,.15)':isSel?'rgba(184,147,90,.18)':'rgba(45,122,79,.13)';pctx.fill();
    pctx.lineWidth=isSel?2:1.5;pctx.strokeStyle=isBooked?'#A33030':isSel?'#B8935A':'#2D7A4F';pctx.stroke();
    pctx.fillStyle=isBooked?'#A33030':isSel?'#8B6914':'#2D7A4F';pctx.textAlign='center';
    if(cf===3){
      pctx.font='bold 11px Inter';pctx.fillText(t.name||'',t.x+t.w/2,t.y+t.h/2-6);
      pctx.font='10px Inter';pctx.fillText(isBooked?'Занято':'Свободно · до '+t.s+' чел.',t.x+t.w/2,t.y+t.h/2+10);
    } else {
      pctx.font='bold 11px Inter';pctx.fillText('№'+t.id,t.x+t.w/2,t.y+t.h/2-5);
      pctx.font='9px Inter';pctx.fillText(t.s+' мест',t.x+t.w/2,t.y+t.h/2+7);
    }
  });
}

if(PC){
  PC.addEventListener('click',function(e){
    const r=PC.getBoundingClientRect(),sx=PC.width/r.width,sy=PC.height/r.height;
    const mx=(e.clientX-r.left)*sx,my=(e.clientY-r.top)*sy;
    const bookedTables=new Set();
    bookings.forEach(b=>{if(b.floor===cf)bookedTables.add(b.tableId);});
    FLOORS[cf].tables.forEach(t=>{
      if(!t.b&&!bookedTables.has(t.id)&&mx>=t.x&&mx<=t.x+t.w&&my>=t.y&&my<=t.y+t.h){
        sel={floor:cf,id:t.id,label:cf===3?(t.name||'VIP'):`Стол №${t.id} — ${cf===1?'Зал 1':'Зал 2'}`,seats:t.s};
        document.getElementById('pSel').innerHTML='&#10022; Выбрано: <strong>'+sel.label+'</strong> · до '+t.s+' гостей';
        drawPlan();
      }
    });
  });

  // Touch support for mobile
  PC.addEventListener('touchstart',function(e){
    e.preventDefault();
    const touch=e.touches[0];
    const r=PC.getBoundingClientRect(),sx=PC.width/r.width,sy=PC.height/r.height;
    const mx=(touch.clientX-r.left)*sx,my=(touch.clientY-r.top)*sy;
    const bookedTables=new Set();
    bookings.forEach(b=>{if(b.floor===cf)bookedTables.add(b.tableId);});
    FLOORS[cf].tables.forEach(t=>{
      if(!t.b&&!bookedTables.has(t.id)&&mx>=t.x&&mx<=t.x+t.w&&my>=t.y&&my<=t.y+t.h){
        sel={floor:cf,id:t.id,label:cf===3?(t.name||'VIP'):`Стол №${t.id} — ${cf===1?'Зал 1':'Зал 2'}`,seats:t.s};
        document.getElementById('pSel').innerHTML='&#10022; Выбрано: <strong>'+sel.label+'</strong> · до '+t.s+' гостей';
        drawPlan();
      }
    });
  },{passive:false});
}

