if(bPhoneEl){
  bPhoneEl.addEventListener('input',e=>{
    let v=e.target.value.replace(/\D/g,'');
    if(v.length>0){
      if(v[0]==='7'||v[0]==='8')v=v.substring(1);
      let formatted='+7';
      if(v.length>0)formatted+=' ('+v.substring(0,3);
      if(v.length>=3)formatted+=') '+v.substring(3,6);
      if(v.length>=6)formatted+='-'+v.substring(6,8);
      if(v.length>=8)formatted+='-'+v.substring(8,10);
      e.target.value=formatted;
    }
  });
}

// Form validation
function validateBookingForm(){
  let valid=true;
  const nameEl=document.getElementById('bName');
  const phoneEl=document.getElementById('bPhone');
  const dateEl=document.getElementById('bDate');

  [nameEl,phoneEl,dateEl].forEach(el=>el.classList.remove('invalid'));

  if(!sel){showToast('Выберите стол на плане');return false;}
  if(!nameEl.value.trim()){nameEl.classList.add('invalid');valid=false;}
  if(!phoneEl.value.trim()||phoneEl.value.replace(/\D/g,'').length<10){phoneEl.classList.add('invalid');valid=false;}
  if(!dateEl.value){dateEl.classList.add('invalid');valid=false;}
  return valid;
}

function submitBooking(){
  if(!validateBookingForm())return;

  const btn=document.getElementById('bookBtn');btn.disabled=true;btn.textContent='Отправляем...';

  const booking={
    name:document.getElementById('bName').value.trim(),
    phone:document.getElementById('bPhone').value.trim(),
    date:document.getElementById('bDate').value,
    time:document.getElementById('bTime').value,
    guests:document.getElementById('bGuests').value,
    wish:document.getElementById('bWish').value.trim(),
    tableId:sel.id,
    floor:cf,
    label:sel.label
  };

  fetch(API_BASE+'/api/bookings',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(booking)})
    .then(r=>r.json())
    .then(data=>{
      if(!data.ok){showToast(data.error||'Ошибка бронирования');btn.disabled=false;btn.textContent='ЗАБРОНИРОВАТЬ СТОЛ';return;}
      bookings.push(data.booking);
      sel=null;
      document.getElementById('pSel').innerHTML='&larr; Нажмите на свободный стол';
      document.getElementById('bookNum').textContent=data.booking.id;
      document.getElementById('bookOk').style.display='block';
      btn.style.display='none';
      drawPlan();
      updateMyBookings();
      document.getElementById('bName').value='';
      document.getElementById('bPhone').value='';
      document.getElementById('bWish').value='';
      setTimeout(()=>{
        btn.disabled=false;btn.textContent='ЗАБРОНИРОВАТЬ СТОЛ';btn.style.display='block';
        document.getElementById('bookOk').style.display='none';
      },4000);
    })
    .catch(()=>{showToast('Ошибка сети');btn.disabled=false;btn.textContent='ЗАБРОНИРОВАТЬ СТОЛ';});
}

function cancelBooking(){
  const val=document.getElementById('cancelInput').value.trim();
  const msg=document.getElementById('cancelMsg');
  function showMsg(text,color){msg.style.display='block';msg.style.color=color;msg.textContent=text;setTimeout(()=>{msg.style.display='none';},4000);}
  if(!val){showMsg('Введите номер брони или телефон','#A33030');return;}
  const b=bookings.find(b=>b.id===val.toUpperCase()||b.phone===val);
  if(b){
    fetch(API_BASE+'/api/bookings/'+b.id,{method:'DELETE'})
      .then(r=>r.json())
      .then(()=>{
        bookings=bookings.filter(x=>x.id!==b.id);
        showMsg('Бронь '+b.id+' отменена.','#2D7A4F');
        if(cf===b.floor)drawPlan();
        updateMyBookings();
      })
      .catch(()=>{showMsg('Ошибка сети.','#A33030');});
  } else {
    showMsg('Бронь не найдена.','#A33030');
  }
}

function updateMyBookings(){
  const container=document.getElementById('myBookings');
  const list=document.getElementById('myBookingsList');
  if(!container||!list)return;
  if(bookings.length===0){container.style.display='none';return;}
  container.style.display='block';
  list.innerHTML=bookings.map(b=>`
    <div class="booking-card">
      <strong>${b.id}</strong> — ${b.label}<br>
      ${b.date} в ${b.time}, ${b.guests} гостей<br>
      ${b.name}, ${b.phone}
      <button class="booking-cancel" onclick="cancelBookingById('${b.id}')">Отменить</button>
    </div>`).join('');
}

function cancelBookingById(id){
  fetch(API_BASE+'/api/bookings/'+id,{method:'DELETE'})
    .then(r=>r.json())
    .then(()=>{
      bookings=bookings.filter(b=>b.id!==id);
      drawPlan();
      updateMyBookings();
      showToast('Бронь '+id+' отменена');
    });
}

