// ========== ADMIN AUTH ==========
let adminAuthenticated=false;

async function checkAdminAuth(){
  try{
    const r=await fetch(API_BASE+'/api/auth/check');
    const data=await r.json();
    adminAuthenticated=data.auth||false;
  }catch(e){adminAuthenticated=false;}
}

function openAdmin(){
  if(adminAuthenticated){
    document.getElementById('adminOverlay').classList.add('open');
    document.body.style.overflow='hidden';
    switchAdminTab('bookings',document.querySelector('.admin-tab'));
  } else {
    openAdminLogin();
  }
}

function closeAdmin(){
  document.getElementById('adminOverlay').classList.remove('open');
  document.body.style.overflow='';
}

function openAdminLogin(){
  document.getElementById('adminLoginOverlay').classList.add('open');
  document.body.style.overflow='hidden';
  const inputs=document.querySelectorAll('.pin-input');
  inputs.forEach(i=>{i.value='';});
  inputs[0].focus();
}

function closeAdminLogin(){
  document.getElementById('adminLoginOverlay').classList.remove('open');
  document.body.style.overflow='';
  document.getElementById('pinError').textContent='';
}

document.addEventListener('DOMContentLoaded',()=>{
  const pinInputs=document.querySelectorAll('.pin-input');
  pinInputs.forEach((input,idx)=>{
    input.addEventListener('input',e=>{
      const val=e.target.value.replace(/\D/g,'');
      e.target.value=val;
      if(val&&idx<pinInputs.length-1)pinInputs[idx+1].focus();
      if(idx===pinInputs.length-1&&val)submitPin();
    });
    input.addEventListener('keydown',e=>{
      if(e.key==='Backspace'&&!e.target.value&&idx>0)pinInputs[idx-1].focus();
      if(e.key==='Enter')submitPin();
    });
    input.addEventListener('paste',e=>{
      e.preventDefault();
      const paste=(e.clipboardData||window.clipboardData).getData('text').replace(/\D/g,'').slice(0,4);
      paste.split('').forEach((ch,i)=>{if(pinInputs[i])pinInputs[i].value=ch;});
      if(paste.length>0)pinInputs[Math.min(paste.length,3)].focus();
      if(paste.length>=4)submitPin();
    });
  });
});

async function submitPin(){
  const inputs=document.querySelectorAll('.pin-input');
  const pin=Array.from(inputs).map(i=>i.value).join('');
  const errEl=document.getElementById('pinError');
  if(pin.length<4){errEl.textContent='Введите 4 цифры';return;}
  errEl.textContent='';
  try{
    const r=await fetch(API_BASE+'/api/auth/login',{
      method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({pin})
    });
    const data=await r.json();
    if(data.ok){
      adminAuthenticated=true;
      closeAdminLogin();
      document.getElementById('adminOverlay').classList.add('open');
      document.body.style.overflow='hidden';
      switchAdminTab('bookings',document.querySelector('.admin-tab'));
    } else {
      errEl.textContent=data.error||'Неверный PIN';
      inputs.forEach(i=>{i.value='';});
      inputs[0].focus();
    }
  }catch(e){errEl.textContent='Ошибка сети';}
}

async function adminLogout(){
  await fetch(API_BASE+'/api/auth/logout',{method:'POST'});
  adminAuthenticated=false;
  closeAdmin();
  showToast('Вы вышли из админ-панели');
}

let adminTab='bookings';
function switchAdminTab(tab,el){
  adminTab=tab;
  document.querySelectorAll('.admin-tab').forEach(t=>{t.classList.remove('on');});
  if(el)el.classList.add('on');
  renderAdmin();
}

function renderAdmin(){
  const body=document.getElementById('adminBody');

  if(adminTab==='menu'){renderAdminMenuTab();return;}
  if(adminTab==='gallery'){renderAdminGalleryTab();return;}
  if(adminTab==='content'){renderAdminContentTab();return;}
  if(adminTab==='reviews'){renderAdminReviewsTab();return;}

  Promise.all([
    fetch(API_BASE+'/api/bookings').then(r=>r.json()).catch(()=>({bookings:[]})),
    fetch(API_BASE+'/api/orders').then(r=>r.json()).catch(()=>({orders:[]}))
  ]).then(([bksData,ordsData])=>{
    const bks=bksData.bookings||[];
    const ords=ordsData.orders||[];

  if(adminTab==='bookings'){
    if(bks.length===0){body.innerHTML='<div class="admin-empty">&#128197;<br>Бронирований пока нет</div>';return;}
    const stats={total:bks.length,confirmed:bks.length};
    body.innerHTML=`
      <div class="admin-stats">
        <div class="admin-stat"><div class="admin-stat-num">${stats.total}</div><div class="admin-stat-lbl">Всего</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${stats.confirmed}</div><div class="admin-stat-lbl">Подтверждено</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${new Set(bks.map(b=>b.date)).size}</div><div class="admin-stat-lbl">Дней</div></div>
      </div>
      <div class="admin-table-wrap"><table class="admin-table">
        <thead><tr><th>Номер</th><th>Имя</th><th>Телефон</th><th>Дата</th><th>Время</th><th>Гости</th><th>Стол</th><th></th></tr></thead>
        <tbody>${bks.map(b=>`<tr>
          <td><strong style="color:var(--gold-d)">${b.id}</strong></td>
          <td>${b.name}</td>
          <td><a href="tel:${b.phone}" style="color:var(--muted)">${b.phone}</a></td>
          <td>${b.date}</td>
          <td>${b.time}</td>
          <td>${b.guests}</td>
          <td>${b.label}</td>
          <td><div class="admin-actions">
            <a href="https://wa.me/${b.phone.replace(/\D/g,'')}" target="_blank" style="padding:4px 8px;border:1px solid #25D366;color:#25D366;border-radius:8px;font-size:10px;text-decoration:none">WA</a>
            <a href="tel:${b.phone}" style="padding:4px 8px;border:1px solid var(--border);color:var(--muted);border-radius:8px;font-size:10px;text-decoration:none">Звонок</a>
            <button class="del-btn" onclick="adminDeleteBooking('${b.id}')">Удалить</button>
          </div></td>
        </tr>`).join('')}</tbody>
      </table></div>`;
  } else if(adminTab==='orders'){
    if(ords.length===0){body.innerHTML='<div class="admin-empty">&#128722;<br>Заказов пока нет</div>';return;}
    const totalRev=ords.reduce((s,o)=>s+o.total,0);
    body.innerHTML=`
      <div class="admin-stats">
        <div class="admin-stat"><div class="admin-stat-num">${ords.length}</div><div class="admin-stat-lbl">Заказов</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${formatPrice(totalRev)}</div><div class="admin-stat-lbl">Выручка (тг)</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${ords.filter(o=>o.type==='here').length}</div><div class="admin-stat-lbl">В зале</div></div>
      </div>
      <div class="admin-table-wrap"><table class="admin-table">
        <thead><tr><th>Номер</th><th>Тип</th><th>Стол</th><th>Состав</th><th>Сумма</th><th>Время</th></tr></thead>
        <tbody>${ords.map(o=>`<tr>
          <td><strong style="color:var(--gold-d)">${o.id}</strong></td>
          <td><span class="admin-badge ${o.type==='here'?'booked':'preparing'}">${o.type==='here'?'В зале':'С собой'}</span></td>
          <td>${o.type==='here'?(o.tableLabel||'Стол №'+o.tableId||'-'):'-'}</td>
          <td>${o.items.map(i=>i.name+' x'+i.qty).join(', ')}</td>
          <td><strong>${formatPrice(o.total)} тг</strong></td>
          <td>${new Date(o.date).toLocaleString('ru')}</td>
        </tr>`).join('')}</tbody>
      </table></div>`;
  } else if(adminTab==='stats'){
    const today=new Date().toISOString().split('T')[0];
    const todayBks=bks.filter(b=>b.date===today);
    const todayOrds=ords.filter(o=>o.date&&o.date.startsWith(today));
    const todayRev=todayOrds.reduce((s,o)=>s+o.total,0);
    const totalRev=ords.reduce((s,o)=>s+o.total,0);
    body.innerHTML=`
      <div class="admin-stats">
        <div class="admin-stat"><div class="admin-stat-num">${todayBks.length}</div><div class="admin-stat-lbl">Броней сегодня</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${todayOrds.length}</div><div class="admin-stat-lbl">Заказов сегодня</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${formatPrice(todayRev)}</div><div class="admin-stat-lbl">Выручка сегодня</div></div>
      </div>
      <div class="admin-stats" style="margin-top:12px">
        <div class="admin-stat"><div class="admin-stat-num">${bks.length}</div><div class="admin-stat-lbl">Всего броней</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${ords.length}</div><div class="admin-stat-lbl">Всего заказов</div></div>
        <div class="admin-stat"><div class="admin-stat-num">${formatPrice(totalRev)}</div><div class="admin-stat-lbl">Общая выручка</div></div>
      </div>
      <div style="margin-top:20px;padding:16px;background:var(--bg);border-radius:12px">
        <p style="font-size:12px;color:var(--muted);margin-bottom:8px">Экспорт данных:</p>
        <button class="btn btn-outline" style="font-size:10px;padding:8px 16px" onclick="exportData()">Скачать JSON</button>
      </div>`;
  }
  });
}

function adminDeleteBooking(id){
  fetch(API_BASE+'/api/bookings/'+id,{method:'DELETE'})
    .then(r=>r.json())
    .then(()=>{
      bookings=bookings.filter(b=>b.id!==id);
      drawPlan();renderAdmin();showToast('Бронь удалена');
    });
}

// ========== POPULAR DISHES ==========
const POPULAR_ITEMS=[7,11,8,12,14,15,23,24];

function renderPopular(){
  const carousel=document.getElementById('popularCarousel');
  const dots=document.getElementById('popularDots');
  if(!carousel)return;
  const allItems=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||MENU;
  const popular=POPULAR_ITEMS.filter(i=>i<allItems.length).map(i=>allItems[i]);
  if(popular.length===0)popular.push(...allItems.slice(0,6));
  window.popularItems=popular;
  carousel.innerHTML=popular.map((item,i)=>{
    const isCustom=item.img?`<img src="${item.img}" alt="${item.name}" style="width:100%;height:100%;object-fit:cover">`:item.emoji;
    return `<div class="pop-card fi d${(i%4)+1}" onclick="openPopularModal(${i})">
      <div class="pop-card-img" style="background:${catColors[item.cat]||'#F5E6DC'}">
        ${isCustom}
        <div class="pop-card-badge">Хит</div>
      </div>
      <div class="pop-card-body">
        <div class="pop-card-name">${item.name}</div>
        <div class="pop-card-desc">${item.desc}</div>
        <div class="pop-card-footer">
          <div class="pop-card-price">${formatPrice(item.price)}<span>тг</span></div>
          <button class="pop-card-add" onclick="event.stopPropagation();addToCart(window.popularItems[${i}],1)" aria-label="Добавить в корзину">+</button>
        </div>
      </div>
    </div>`;
  }).join('');
  if(dots){
    const count=Math.ceil(popular.length/3);
    dots.innerHTML=Array.from({length:Math.max(count,1)},(_,i)=>`<div class="pop-dot${i===0?' active':''}"></div>`).join('');
  }
  setTimeout(initAnim,100);
}

function openPopularModal(idx){
  const item=window.popularItems?window.popularItems[idx]:null;
  if(!item)return;
  modalQty=1;
  const modalImg=document.getElementById('modalImg');
  modalImg.style.background=catColors[item.cat];
  const imgHtml=item.img?`<img src="${item.img}" alt="${item.name}" style="width:100%;height:100%;object-fit:cover">`:item.emoji;
  modalImg.innerHTML='<button class="modal-close" onclick="closeMenuModal()" aria-label="Закрыть">&times;</button>'+imgHtml;
  document.getElementById('modalCat').textContent=catNames[item.cat];
  document.getElementById('modalName').textContent=item.name;
  document.getElementById('modalPrice').textContent=formatPrice(item.price)+' тг';
  document.getElementById('modalDesc').textContent=item.desc;
  document.getElementById('modalQtyInput').value=1;
  document.getElementById('menuModal').classList.add('open');
  document.body.style.overflow='hidden';
  window._modalItem=item;
}

function scrollPopular(dir){
  const carousel=document.getElementById('popularCarousel');
  if(!carousel)return;
  const scrollAmt=280;
  carousel.scrollBy({left:dir*scrollAmt,behavior:'smooth'});
  setTimeout(()=>{
    const dots=document.querySelectorAll('.pop-dot');
    const idx=Math.round(carousel.scrollLeft/scrollAmt);
    dots.forEach((d,i)=>d.classList.toggle('active',i===Math.min(idx,dots.length-1)));
  },350);
}

// ========== ADMIN MENU EDITING ==========
let editingMenuIdx=-1;

function renderAdminMenuTab(){
  const body=document.getElementById('adminBody');
  const menu=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||[...MENU];
  const customCount=menu.filter(m=>m.img).length;
  const totalItems=menu.length;
  const cats=Object.keys(catNames);

  body.innerHTML=`
    <div class="admin-stats">
      <div class="admin-stat"><div class="admin-stat-num">${totalItems}</div><div class="admin-stat-lbl">Блюд</div></div>
      <div class="admin-stat"><div class="admin-stat-num">${cats.length}</div><div class="admin-stat-lbl">Категорий</div></div>
      <div class="admin-stat"><div class="admin-stat-num">${customCount}</div><div class="admin-stat-lbl">С фото</div></div>
    </div>
    <div id="adminMenuForm"></div>
    <div id="adminMenuList"></div>`;
  renderAdminMenuForm(menu);
  renderAdminMenuList(menu);
}

function renderAdminMenuForm(menu){
  const form=document.getElementById('adminMenuForm');
  if(!form)return;
  const cats=Object.keys(catNames);
  if(editingMenuIdx===-1){
    form.innerHTML=`<button class="btn btn-gold" style="font-size:11px;padding:10px 20px;margin-bottom:16px" onclick="showAdminMenuAddForm()">+ Добавить блюдо</button>`;
  } else {
    const item=menu[editingMenuIdx]||{cat:'main',name:'',desc:'',price:'',emoji:'&#127830;',img:''};
    form.innerHTML=`<div class="admin-menu-edit-form">
      <h4 style="font-family:'Source Serif 4',serif;font-size:16px;color:var(--gold-d);margin-bottom:14px">${item._isNew?'Новое блюдо':'Редактирование: '+item.name}</h4>
      <div class="admin-menu-form" style="margin-bottom:0">
        <div class="fg half">
          <label for="admMenuName">Название</label>
          <input type="text" id="admMenuName" value="${item.name||''}" placeholder="Название блюда">
        </div>
        <div class="fg half">
          <label for="admMenuPrice">Цена (тг)</label>
          <input type="number" id="admMenuPrice" value="${item.price||''}" placeholder="0">
        </div>
        <div class="fg full">
          <label for="admMenuDesc">Описание</label>
          <input type="text" id="admMenuDesc" value="${item.desc||''}" placeholder="Описание блюда">
        </div>
        <div class="fg half">
          <label for="admMenuCat">Категория</label>
          <select id="admMenuCat">${cats.map(c=>`<option value="${c}"${item.cat===c?' selected':''}>${catNames[c]}</option>`).join('')}</select>
        </div>
        <div class="fg half">
          <label for="admMenuEmoji">Эмодзи</label>
          <input type="text" id="admMenuEmoji" value="${item.emoji||''}" placeholder="&#127830;" style="font-size:24px;text-align:center">
        </div>
        <div class="fg full">
          <label>Фото блюда</label>
          <label class="admin-photo-upload ${item.img?'has-photo':''}" id="admPhotoLabel">
            ${item.img?`<img src="${item.img}" class="admin-photo-preview">`:'Нажмите или перетащите фото'}
            <input type="file" accept="image/*" style="display:none" id="admPhotoInput" onchange="handleAdminPhoto(event)">
          </label>
        </div>
        <div class="admin-menu-actions">
          <button class="save-btn" onclick="saveAdminMenuItem(${editingMenuIdx})">${item._isNew?'Добавить':'Сохранить'}</button>
          <button class="cancel-btn" onclick="cancelAdminMenuEdit()">Отмена</button>
          ${!item._isNew?`<button class="del-btn" style="padding:8px 18px;border-radius:10px;font-size:11px;letter-spacing:.5px;cursor:pointer;font-family:Inter,sans-serif;font-weight:500;border:none" onclick="deleteAdminMenuItem(${editingMenuIdx})">Удалить</button>`:''}
        </div>
      </div>
    </div>`;
  }
}

function renderAdminMenuList(menu){
  const list=document.getElementById('adminMenuList');
  if(!list)return;
  list.innerHTML=`<table class="admin-table">
    <thead><tr><th></th><th>Название</th><th>Категория</th><th>Цена</th><th></th></tr></thead>
    <tbody>${menu.map((item,i)=>`<tr>
      <td><div class="admin-menu-img" style="background:${catColors[item.cat]||'#F5E6DC'}">
        ${item.img?`<img src="${item.img}" alt="${item.name}">`:(item.emoji||'')}
      </div></td>
      <td><strong>${item.name}</strong><br><span style="font-size:10px;color:var(--muted)">${item.desc.substring(0,40)}${item.desc.length>40?'...':''}</span></td>
      <td>${catNames[item.cat]||item.cat}</td>
      <td><strong style="color:var(--gold-d)">${formatPrice(item.price)} тг</strong></td>
      <td><div class="admin-actions">
        <button onclick="editAdminMenuItem(${i})">Ред.</button>
        <button class="del-btn" onclick="deleteAdminMenuItem(${i})">Уд.</button>
      </div></td>
    </tr>`).join('')}</tbody>
  </table>`;
}

function showAdminMenuAddForm(){
  const menu=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||[...MENU];
  menu.push({cat:'main',name:'',desc:'',price:0,emoji:'&#127830;',img:'',_isNew:true});
  localStorage.setItem('eden_menu_custom',JSON.stringify(menu));
  editingMenuIdx=menu.length-1;
  renderAdminMenuForm(menu);
  renderAdminMenuList(menu);
}

function editAdminMenuItem(idx){
  editingMenuIdx=idx;
  const menu=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||[...MENU];
  renderAdminMenuForm(menu);
  document.querySelector('.admin-menu-edit-form')?.scrollIntoView({behavior:'smooth',block:'nearest'});
}

function cancelAdminMenuEdit(){
  editingMenuIdx=-1;
  const menu=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||[...MENU];
  renderAdminMenuForm(menu);
  renderAdminMenuList(menu);
}

function saveAdminMenuItem(idx){
  const menu=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||[...MENU];
  const item=menu[idx];
  if(!item)return;
  const name=document.getElementById('admMenuName').value.trim();
  const price=parseInt(document.getElementById('admMenuPrice').value)||0;
  const desc=document.getElementById('admMenuDesc').value.trim();
  const cat=document.getElementById('admMenuCat').value;
  const emoji=document.getElementById('admMenuEmoji').value||'&#127830;';
  if(!name){showToast('Введите название блюда');return;}
  if(!price){showToast('Введите цену');return;}
  item.name=name;
  item.price=price;
  item.desc=desc;
  item.cat=cat;
  item.emoji=emoji;
  delete item._isNew;
  localStorage.setItem('eden_menu_custom',JSON.stringify(menu));
  editingMenuIdx=-1;
  showToast('Блюдо сохранено');
  renderAdminMenuForm(menu);
  renderAdminMenuList(menu);
  renderMenu();
  renderPopular();
}

function deleteAdminMenuItem(idx){
  if(!confirm('Удалить это блюдо?'))return;
  const menu=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||[...MENU];
  menu.splice(idx,1);
  localStorage.setItem('eden_menu_custom',JSON.stringify(menu));
  if(editingMenuIdx===idx)editingMenuIdx=-1;
  else if(editingMenuIdx>idx)editingMenuIdx--;
  showToast('Блюдо удалено');
  renderAdminMenuForm(menu);
  renderAdminMenuList(menu);
  renderMenu();
  renderPopular();
}

// ========== ADMIN GALLERY ==========
async function renderAdminGalleryTab(){
  const body=document.getElementById('adminBody');
  body.innerHTML='<div class="admin-empty">Загрузка...</div>';
  try{
    const r=await fetch(API_BASE+'/api/gallery');
    const data=await r.json();
    const gallery=data.gallery||[];
    body.innerHTML=`
      <div class="admin-stats">
        <div class="admin-stat"><div class="admin-stat-num">${gallery.length}</div><div class="admin-stat-lbl">Фото</div></div>
      </div>
      <div style="margin-bottom:16px">
        <label class="admin-photo-upload" id="galUploadLabel" style="max-width:400px">
          Нажмите или перетащите фото для загрузки
          <input type="file" accept="image/*" style="display:none" id="galUploadInput" onchange="uploadGalleryPhoto(event)">
        </label>
      </div>
      <div class="admin-gallery-grid" id="adminGalleryGrid">
        ${gallery.map(g=>`
          <div class="admin-gallery-item" data-id="${g.id}">
            <img src="${g.src}" alt="${g.label||''}" loading="lazy">
            <div class="admin-gallery-overlay">
              <input type="text" value="${g.label||''}" placeholder="Подпись..." class="gal-label-input" onchange="updateGalleryLabel('${g.id}',this.value)">
              <button class="del-btn" onclick="deleteGalleryItem('${g.id}')" title="Удалить">&#10005;</button>
            </div>
          </div>
        `).join('')}
      </div>
      ${gallery.length===0?'<div class="admin-empty">Галерея пуста. Загрузите первое фото.</div>':''}`;
  }catch(e){body.innerHTML='<div class="admin-empty">Ошибка загрузки</div>';}
}

async function uploadGalleryPhoto(e){
  const file=e.target.files[0];
  if(!file)return;
  if(file.size>10*1024*1024){showToast('Фото слишком большое (макс 10 МБ)');return;}
  const formData=new FormData();
  formData.append('photo',file);
  formData.append('label','');
  try{
    showToast('Загрузка...');
    const r=await fetch(API_BASE+'/api/gallery',{method:'POST',body:formData});
    const data=await r.json();
    if(data.ok){showToast('Фото загружено');renderAdminGalleryTab();loadGallery();} 
    else showToast(data.error||'Ошибка загрузки');
  }catch(ex){showToast('Ошибка сети');}
  e.target.value='';
}

async function deleteGalleryItem(id){
  if(!confirm('Удалить это фото?'))return;
  try{
    await fetch(API_BASE+'/api/gallery/'+id,{method:'DELETE'});
    showToast('Фото удалено');
    renderAdminGalleryTab();
    loadGallery();
  }catch(e){showToast('Ошибка');}
}

async function updateGalleryLabel(id,label){
  try{
    await fetch(API_BASE+'/api/gallery/'+id,{
      method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({label})
    });
    showToast('Подпись обновлена');
  }catch(e){}
}

