async function changeAdminPin(){
  const currentPin=document.getElementById('cntOldPin').value.trim();
  const newPin=document.getElementById('cntNewPin').value.trim();
  if(!currentPin||!newPin){showToast('Заполните оба поля');return;}
  if(newPin.length<4){showToast('PIN должен быть минимум 4 цифры');return;}
  try{
    const r=await fetch(API_BASE+'/api/auth/change-pin',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({currentPin,newPin})
    });
    const data=await r.json();
    if(data.ok){
      showToast('PIN изменён. Войдите заново.');
      await fetch(API_BASE+'/api/auth/logout',{method:'POST'});
      adminAuthenticated=false;
      closeAdmin();
    } else showToast(data.error||'Ошибка');
  }catch(e){showToast('Ошибка сети');}
}

async function loadContent(){
  try{
    const r=await fetch(API_BASE+'/api/content');
    const data=await r.json();
    if(data.ok&&data.content)applyContent(data.content);
  }catch(e){}
}

function applyContent(c){
  if(!c)return;
  const heroEye=document.querySelector('.hero-eye');
  if(heroEye&&c.heroEye)heroEye.textContent=c.heroEye;
  const heroSub=document.querySelector('.hero-sub');
  if(heroSub&&c.heroText)heroSub.textContent=c.heroText;
  const statNums=document.querySelectorAll('.stat-num');
  if(statNums.length>=4){
    if(c.seats)statNums[0].textContent=c.seats;
    if(c.vipRooms)statNums[1].textContent=c.vipRooms;
  }
  document.querySelectorAll('.copyright-year').forEach(el=>el.textContent=new Date().getFullYear());
  const cy=document.getElementById('copyrightYear');
  if(cy)cy.textContent=new Date().getFullYear();
}

// ========== ADMIN REVIEWS ==========
async function renderAdminReviewsTab(){
  const body=document.getElementById('adminBody');
  body.innerHTML='<div class="admin-empty">Загрузка...</div>';
  try{
    const r=await fetch(API_BASE+'/api/reviews');
    const data=await r.json();
    const reviews=data.reviews||[];
    body.innerHTML=`
      <div class="admin-stats">
        <div class="admin-stat"><div class="admin-stat-num">${reviews.length}</div><div class="admin-stat-lbl">Отзывов</div></div>
      </div>
      <div class="admin-review-form" style="margin-bottom:20px;background:var(--bg);padding:18px;border-radius:14px">
        <h4 style="font-family:'Source Serif 4',serif;font-size:14px;color:var(--gold-d);margin-bottom:12px">Добавить отзыв</h4>
        <div class="admin-menu-form" style="margin-bottom:0;background:transparent;padding:0">
          <div class="fg half"><label>Имя</label><input type="text" id="revName" placeholder="Имя гостя"></div>
          <div class="fg half"><label>Источник</label><input type="text" id="revSource" placeholder="2GIS, Google..."></div>
          <div class="fg full"><label>Текст отзыва</label><textarea id="revText" style="min-height:60px;width:100%;padding:10px;border:1px solid var(--border);border-radius:10px;font-family:Inter,sans-serif;font-size:13px" placeholder="Текст отзыва..."></textarea></div>
          <div class="fg half"><label>Оценка</label><select id="revRating"><option value="5">5 звёзд</option><option value="4">4 звезды</option><option value="3">3 звезды</option></select></div>
          <div class="admin-menu-actions"><button class="save-btn" onclick="addReview()">Добавить</button></div>
        </div>
      </div>
      <table class="admin-table">
        <thead><tr><th>Автор</th><th>Текст</th><th>Источник</th><th></th></tr></thead>
        <tbody>${reviews.map(r=>`<tr>
          <td><strong>${r.name}</strong><br><span style="font-size:10px;color:var(--muted)">${r.date||''}</span></td>
          <td style="max-width:300px">${r.text.substring(0,80)}${r.text.length>80?'...':''}</td>
          <td>${r.source||''}</td>
          <td><button class="del-btn" onclick="deleteReview('${r.id}')">Удалить</button></td>
        </tr>`).join('')}</tbody>
      </table>
      ${reviews.length===0?'<div class="admin-empty">Отзывов пока нет</div>':''}`;
  }catch(e){body.innerHTML='<div class="admin-empty">Ошибка загрузки</div>';}
}

async function addReview(){
  const name=document.getElementById('revName').value.trim();
  const text=document.getElementById('revText').value.trim();
  const source=document.getElementById('revSource').value.trim();
  const rating=parseInt(document.getElementById('revRating').value);
  if(!name||!text){showToast('Заполните имя и текст');return;}
  try{
    await fetch(API_BASE+'/api/reviews',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({name,text,source,rating})
    });
    showToast('Отзыв добавлен');
    renderAdminReviewsTab();
  }catch(e){showToast('Ошибка');}
}

async function deleteReview(id){
  if(!confirm('Удалить отзыв?'))return;
  try{
    await fetch(API_BASE+'/api/reviews/'+id,{method:'DELETE'});
    showToast('Отзыв удалён');
    renderAdminReviewsTab();
  }catch(e){showToast('Ошибка');}
}

function handleAdminPhoto(e){
  const file=e.target.files[0];
  if(!file)return;
  if(file.size>10*1024*1024){showToast('Фото слишком большое (макс 10 МБ)');return;}
  const reader=new FileReader();
  reader.onload=function(ev){
    const menu=JSON.parse(localStorage.getItem('eden_menu_custom')||'null')||[...MENU];
    if(editingMenuIdx>=0&&editingMenuIdx<menu.length){
      menu[editingMenuIdx].img=ev.target.result;
      localStorage.setItem('eden_menu_custom',JSON.stringify(menu));
      const label=document.getElementById('admPhotoLabel');
      if(label){label.classList.add('has-photo');label.innerHTML=`<img src="${ev.target.result}" class="admin-photo-preview"><input type="file" accept="image/*" style="display:none" id="admPhotoInput" onchange="handleAdminPhoto(event)">`;}
      showToast('Фото добавлено');
    }
  };
  reader.readAsDataURL(file);
}

// ========== OVERRIDES ==========
const _origRenderMenu=renderMenu;
renderMenu=function(){
  const items=getFilteredMenu();
  const grid=document.getElementById('menuGrid');
  const empty=document.getElementById('menuEmpty');
  if(!grid)return;
  if(items.length===0){grid.innerHTML='';if(empty)empty.style.display='block';return;}
  if(empty)empty.style.display='none';
  grid.innerHTML=items.map((item,i)=>{
    const imgHtml=item.img?`<img src="${item.img}" alt="${item.name}" style="width:100%;height:100%;object-fit:cover">`:item.emoji;
    return `<div class="mitem" onclick="openMenuModal(${i})" tabindex="0" role="button" aria-label="${item.name}, ${formatPrice(item.price)} тг">
      <div class="mitem-img" style="background:${catColors[item.cat]}">${imgHtml}</div>
      <div class="mitem-body">
        <div class="mcat-tag">${catNames[item.cat]}</div>
        <div class="mname">${item.name}</div>
        <div class="mdesc">${item.desc}</div>
        <div class="mprice">${formatPrice(item.price)}<span>тг</span></div>
      </div>
    </div>`;
  }).join('');
  window.currentMenuItems=items;
};

// ========== REVIEWS ON HOMEPAGE ==========
let reviewsData=[];

async function loadReviews(){
  try{
    const r=await fetch(API_BASE+'/api/reviews');
    const data=await r.json();
    reviewsData=data.reviews||[];
  }catch(e){reviewsData=[];}
  renderReviewsOnHome();
}

function renderReviewsOnHome(){
  const grid=document.getElementById('reviewsGrid');
  if(!grid)return;
  const defaultReviews=[
    {name:'Maira Maira',text:'Добрый день! Я сегодня заказала салаты, баурсаки, хлебную корзину. Всё так вкусно, рахмет вам большое. Приветствие с дверей администратора на высоте.',source:'2GIS',rating:5,avatar:'M',color:'#B8935A'},
    {name:'Серик А. & Simpatikus',text:'Очень уютно красиво и вкусно у вас. Обстановка уютная. Всем кто хочет очень вкусно покушать — рекомендую, не пожалеете.',source:'2GIS · 97 отзывов',rating:5,avatar:'C',color:'#5A8AB8'},
    {name:'Акмарал Боранова',text:'Здесь очень вкусно, хорошая атмосфера, вкусная кухня, шашлыки супер!',source:'2GIS · подтверждённый',rating:5,avatar:'A',color:'#7AAB6A'}
  ];
  const reviews=reviewsData.length>0?reviewsData:defaultReviews;
  grid.innerHTML=reviews.map((r,i)=>{
    const stars='&#9733;'.repeat(r.rating||5);
    const initials=r.name.charAt(0).toUpperCase();
    const colors=['#B8935A','#5A8AB8','#7AAB6A','#A33030','#8B6914'];
    const bgColor=r.color||colors[i%colors.length];
    return `<article class="review-card fi d${(i%3)+1}">
      <div class="rv-stars" aria-label="${r.rating||5} из 5 звёзд">${stars}</div>
      <blockquote class="rv-text">&laquo;${r.text}&raquo;</blockquote>
      <div class="rv-author">
        <div class="rv-avatar" style="background:${bgColor};" aria-hidden="true">${initials}</div>
        <div><div class="rv-name">${r.name}</div><div class="rv-date">${r.date||''}</div><div class="rv-source">${r.source||''}</div></div>
      </div>
    </article>`;
  }).join('');
  setTimeout(initAnim,100);
}

// ========== REAL-TIME BOOKING SYNC ==========
let bookingPollInterval=null;
function startBookingPoll(){
  if(bookingPollInterval)return;
  bookingPollInterval=setInterval(async()=>{
    try{
      const r=await fetch(API_BASE+'/api/bookings');
      const data=await r.json();
      if(data.ok){
        const prev=JSON.stringify(bookings);
        bookings=data.bookings;
        if(JSON.stringify(bookings)!==prev){drawPlan();updateMyBookings();populateTableSelect();}
      }
    }catch(e){}
  },15000);
}

// ========== INIT ==========
document.addEventListener('DOMContentLoaded',async()=>{
  const savedMenu=localStorage.getItem('eden_menu_custom');
  if(savedMenu){
    try{const parsed=JSON.parse(savedMenu);if(Array.isArray(parsed)&&parsed.length>0){MENU.length=0;parsed.forEach(m=>MENU.push(m));}}catch(e){}
  }
  await checkAdminAuth();
  await loadBookings();
  await loadContent();
  await loadGallery();
  await loadReviews();
  updateCartUI();
  updateMyBookings();
  renderPopular();
  startBookingPoll();
  if(typeof ymaps==='undefined')loadYandexMaps();else initMap();
  setTimeout(initAnim,200);
});

// Swipe for popular carousel
(function(){
  const c=document.getElementById('popularCarousel');
  if(!c)return;
  let sx=0;
  c.addEventListener('touchstart',e=>{sx=e.touches[0].clientX;},{passive:true});
  c.addEventListener('touchend',e=>{
    const dx=e.changedTouches[0].clientX-sx;
    if(Math.abs(dx)>50){
      c.scrollBy({left:dx>0?-280:280,behavior:'smooth'});
      setTimeout(()=>{
        const dots=document.querySelectorAll('.pop-dot');
        const idx=Math.round(c.scrollLeft/280);
        dots.forEach((d,i)=>d.classList.toggle('active',i===Math.min(idx,dots.length-1)));
      },350);
    }
  },{passive:true});
})();
